from sympy import integer_log, prime
from oeis_sequences.OEISsequences import bisection
def A335331(n):
    ptuple = (2, 3, 5, 7)
    def g(x, m): return sum(g(x//(ptuple[m]**i), m-1)for i in range(integer_log(x, ptuple[m])[0]+1)) if m else x.bit_length()
    return prime(bisection(lambda x:n+x-g(x,3),n,n)) # _Chai Wah Wu_, Mar 15 2026

